const obj = {
  name: 'Объект',
  greet() {
    return 'Привет от ' + this.name
  }
}

// Тест 1: неявная привязка
obj.greet()

// Тест 2: потеря контекста
const fn = obj.greet
fn()

// Тест 3: явная привязка
fn.call({ name: 'Алиса' })

// Тест 4: bind
const bound = fn.bind({ name: 'Боб' })
bound()
